#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        long long *arr = (long long*)malloc(sizeof(long long)*N);
        for(int i=0;i<N;++i) scanf("%lld", &arr[i]);
        int P; scanf("%d", &P);
        if(P<0 || P>=N){
            printf("Invalid Position");
        } else {
            int first = 1;
            for(int i=0;i<N;++i){
                if(i==P) continue;
                if(!first) printf(" ");
                printf("%lld", arr[i]);
                first = 0;
            }
        }
        if(T) printf("\n");
        free(arr);
    }
    return 0;
}

