import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        arr = [int(next(it)) for _ in range(N)]
        P = int(next(it))
        if P < 0 or P >= N:
            out_lines.append('Invalid Position')
        else:
            new_arr = arr[:P] + arr[P+1:]
            out_lines.append(' '.join(map(str, new_arr)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

